sql:
SELECT MAX(chest_bust) AS max_chest_bust
  FROM size_standards
  WHERE clothing_type_id = 1;

external_knowledge:
- 'Current measurements' refers to the most recent measurements taken for each customer and clothing type; 
- 'Recommended sizes' and 'confidence scores' are generated based on customer measurements and clothing types;
- 'Average fit ratings' are calculated from customer feedback, and 'N/A' is displayed if no feedback is available.

sql:
SELECT customer_name
FROM customers
ORDER BY customer_name ASC;

SELECT last_purchase_date
FROM customers
WHERE customer_id = 123;

SELECT MAX(date_generated)
  FROM size_recommendations
  WHERE customer_id = 1;

SELECT customer_id, MAX(date_taken) AS latest_measurement_date
FROM customer_measurements
GROUP BY customer_id;
